// ============================================================
// DSGVO-KONFORME ARCHIVIERUNG
//
// Prueft Schueler auf Archivierungsreife:
// - Status 'bestanden' oder 'abgemeldet' oder 'storniert'
// - Letzte Aktivitaet > 6 Monate her (Aufbewahrungsfrist)
// - ODER: Opt-Out und > 30 Tage inaktiv
//
// Personenbezogene Daten werden anonymisiert:
// - Telefon -> letzte 4 Ziffern behalten
// - Email -> entfernt
// - Name -> Initialen
// - Adresse -> entfernt
// ============================================================
const schueler = $input.all();
const now = new Date();
const AUFBEWAHRUNG_MONATE = 6;
const OPT_OUT_TAGE = 30;

const zuArchivieren = [];

for (const item of schueler) {
  const d = item.json;
  const status = (d.Status || d.status || '').toLowerCase();
  const optOut = (d.WA_Opt_Out || d.wa_opt_out || '').toString().toLowerCase() === 'ja' || d.wa_opt_out === true;
  const name = d.Name || d.Schueler || d.vorname && d.nachname ? `${d.vorname} ${d.nachname}` : '';
  const telefon = (d.Telefon || d.telefon || '').toString();
  const email = d.Email || d.email || '';
  const schuelerId = d.Schueler_ID || d.id || '';
  const klasse = d.Klasse || d.klasse || '';

  // Bestimmung des 'End-Datums'
  let endDatum = null;
  const bestandenDatum = d.Pruefung_Bestanden || d.pruefung_bestanden || '';
  const anmeldeDatum = d.Anmelde_Datum || d.anmelde_datum || d.created_at || '';
  const optOutDatum = d.WA_Opt_Out_Datum || d.wa_opt_out_datum || '';

  if (status === 'bestanden' && bestandenDatum) {
    try { endDatum = new Date(bestandenDatum); } catch(e) {}
  } else if (status === 'abgemeldet' || status === 'storniert') {
    // Anmeldedatum als Referenz wenn kein besseres Datum
    try { endDatum = new Date(anmeldeDatum); } catch(e) {}
  }

  if (!endDatum || isNaN(endDatum.getTime())) continue;

  const monateSeitEnde = (now.getTime() - endDatum.getTime()) / (1000 * 60 * 60 * 24 * 30);

  let archivGrund = '';

  if (monateSeitEnde >= AUFBEWAHRUNG_MONATE && (status === 'bestanden' || status === 'abgemeldet' || status === 'storniert')) {
    archivGrund = `Aufbewahrungsfrist abgelaufen (${Math.round(monateSeitEnde)} Monate seit ${status})`;
  } else if (optOut && optOutDatum) {
    try {
      const optOutDate = new Date(optOutDatum);
      const tageSeitOptOut = (now.getTime() - optOutDate.getTime()) / (1000 * 60 * 60 * 24);
      if (tageSeitOptOut >= OPT_OUT_TAGE) {
        archivGrund = `Opt-Out vor ${Math.round(tageSeitOptOut)} Tagen, Kontaktdaten anonymisieren`;
      }
    } catch(e) {}
  }

  if (!archivGrund) continue;

  // Anonymisierung
  const telefonAnonym = telefon.length > 4 ? '***' + telefon.slice(-4) : '***';
  const nameInitialen = name.split(' ').map(t => t.charAt(0) + '.').join(' ');

  zuArchivieren.push({
    json: {
      schuelerId,
      originalName: name,
      nameAnonymisiert: nameInitialen,
      telefonAnonymisiert: telefonAnonym,
      klasse,
      status,
      archivGrund,
      archivDatum: now.toISOString()
    }
  });
}

return zuArchivieren.length > 0 ? zuArchivieren : [{ json: { skip: true, anzahlGeprueft: schueler.length } }];

